  t.escalation_threshold_hours
FROM approval_gates t;

CREATE OR REPLACE VIEW vw_roles WITH (security_invoker = ON) AS
SELECT
  t.role_id,
  t.label,
  t.comment,
  t.department,
  t.filled_by,
  t.workflow_steps,
  calc_roles_count_of_workflow_steps(t.role_id) AS count_of_workflow_steps,
  t.delegates_to,
  calc_roles_delegates_to_label(t.role_id) AS delegates_to_label,
  calc_roles_filled_by_name(t.role_id) AS filled_by_name,
  calc_roles_filled_by_m_box(t.role_id) AS filled_by_m_box,
  t.delegated_to_by
FROM roles t;

CREATE OR REPLACE VIEW vw_agents WITH (security_invoker = ON) AS
SELECT
  t.agent_id,
  t.name,
  t.type_of_agent,
